ALTER TABLE `attribute_metrics_summaries` ADD COLUMN `total_work_units` AggregateFunction(sumIf, Float64, UInt8);
ALTER TABLE `attribute_metrics_summaries` ADD COLUMN `scored_cost` AggregateFunction(sumIf, Float64, UInt8);
ALTER TABLE `attribute_metrics_summaries` ADD COLUMN `scored_tokens` AggregateFunction(sumIf, Int64, UInt8);
-- drop "attribute_metrics_summaries_mv" view
DROP VIEW `attribute_metrics_summaries_mv`;
-- create "attribute_metrics_summaries_mv" view
CREATE MATERIALIZED VIEW `attribute_metrics_summaries_mv` TO `attribute_metrics_summaries` AS WITH toUnixTimestamp64Nano(toDateTime64('2026-07-14 00:00:00', 9, 'UTC')) AS attribute_metrics_cutoff_unix_nano, gram_urn = 'claude-code:otel:logs' AS is_claude_otel_row, is_claude_otel_row AND (chat_id != '') AND (toString(attributes.prompt.id) != '') AND ((toString(attributes.event.name) = 'api_request') OR (body = 'claude_code.api_request')) AS is_claude_api_request, is_claude_otel_row AND ((toString(attributes.event.name) = 'tool_result') OR (body = 'claude_code.tool_result')) AS is_claude_tool_result, gram_urn = 'codex:otel:logs' AS is_codex_otel_row, is_codex_otel_row AND (toString(attributes.event.name) = 'codex.sse_event') AND (toString(attributes.event.kind) = 'response.completed') AND ((toString(attributes.input_token_count) != '') OR (toString(attributes.output_token_count) != '')) AS is_codex_api_request, least(greatest(toInt64OrZero(toString(attributes.cached_token_count)), 0), greatest(toInt64OrZero(toString(attributes.input_token_count)), 0)) AS codex_cache_read_tokens, greatest(toInt64OrZero(toString(attributes.input_token_count)), 0) - codex_cache_read_tokens AS codex_input_tokens, startsWith(gram_urn, 'codex:usage') OR startsWith(gram_urn, 'cursor:usage') OR startsWith(gram_urn, 'claude_chat:usage') OR startsWith(gram_urn, 'claude_chat:cost') AS is_agent_usage_row, is_claude_api_request OR is_codex_api_request OR is_agent_usage_row AS is_usage_row, (toString(attributes.gram.hook.source) IN ('codex', 'cursor')) AND (toString(attributes.gram.tool.name) != '') AND (toString(attributes.gram.tool.name) NOT IN ('claude-code', 'codex', 'cursor')) AND (toString(attributes.gram.hook.event) IN ('PostToolUse', 'PostToolUseFailure')) AS is_agent_tool_call, is_claude_tool_result OR is_agent_tool_call AS is_counted_tool_call, multiIf(toString(attributes.tool_use_id) != '', toString(attributes.tool_use_id), toString(attributes.gen_ai.tool.call.id) != '', toString(attributes.gen_ai.tool.call.id), toString(id)) AS tool_call_dedup_id, gram_urn = 'chat_analysis:work_units:score' AS is_work_units_score SELECT gram_project_id, toStartOfHour(fromUnixTimestamp64Nano(time_unix_nano)) AS time_bucket, toString(attributes.user.attributes.department_name) AS department_name, toString(attributes.user.attributes.job_title) AS job_title, toString(attributes.user.attributes.employee_type) AS employee_type, toString(attributes.user.attributes.division_name) AS division_name, toString(attributes.user.attributes.cost_center_name) AS cost_center_name, user_email AS user_email, multiIf(is_claude_api_request AND (toString(attributes.model) != ''), toString(attributes.model), is_claude_api_request AND (toString(attributes.gen_ai.request.model) != ''), toString(attributes.gen_ai.request.model), toString(attributes.gen_ai.response.model)) AS model, hook_source, arraySort(JSONExtract(ifNull(toJSONString(attributes.user.roles), '[]'), 'Array(String)')) AS roles, arraySort(JSONExtract(ifNull(toJSONString(attributes.user.groups), '[]'), 'Array(String)')) AS groups, uniqExactIfState(toString(attributes.gen_ai.conversation.id), (toString(attributes.gen_ai.conversation.id) != '') AND is_usage_row) AS total_chats, sumIfState(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.input_tokens)), is_codex_api_request, codex_input_tokens, toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens))), is_usage_row) AS total_input_tokens, sumIfState(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.output_tokens)), is_codex_api_request, toInt64OrZero(toString(attributes.output_token_count)), toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))), is_usage_row) AS total_output_tokens, sumIfState(multiIf(is_claude_api_request, (toInt64OrZero(toString(attributes.input_tokens)) + toInt64OrZero(toString(attributes.output_tokens))) + toInt64OrZero(toString(attributes.cache_creation_tokens)), is_codex_api_request, codex_input_tokens + toInt64OrZero(toString(attributes.output_token_count)), (toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens)) + toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))) + toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS total_tokens, sumIfState(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.cache_read_tokens)), is_codex_api_request, codex_cache_read_tokens, toInt64OrZero(toString(attributes.gen_ai.usage.cache_read.input_tokens))), is_usage_row) AS cache_read_input_tokens, sumIfState(if(is_claude_api_request, toInt64OrZero(toString(attributes.cache_creation_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS cache_creation_input_tokens, sumIfState(if(is_claude_api_request, multiIf(toString(attributes.cost_usd) != '', toFloat64OrZero(toString(attributes.cost_usd)), toString(attributes.cost_usd_micros) != '', toFloat64OrZero(toString(attributes.cost_usd_micros)) / 1000000, 0), toFloat64OrZero(toString(attributes.gen_ai.usage.cost))), is_usage_row) AS total_cost, countIfState(is_counted_tool_call) AS total_tool_calls, uniqExactIfState(tool_call_dedup_id, is_counted_tool_call) AS unique_tool_calls, account_type, provider, billing_mode, if(is_claude_api_request, toString(attributes.query_source), '') AS query_source, if(is_claude_api_request, toString(attributes.skill.name), '') AS skill_name, if(is_claude_api_request, toString(attributes.agent.name), '') AS agent_name, if(is_claude_api_request, toString(attributes.mcp_server.name), '') AS mcp_server_name, if(is_claude_api_request, toString(attributes.mcp_tool.name), '') AS mcp_tool_name, toUInt8(2) AS generation, toUInt8(1) AS is_active, toString(attributes.gram.hook.hostname) AS hook_hostname, sumIfState(toFloat64OrZero(toString(attributes.gram.chat_analysis.work_units)), is_work_units_score) AS total_work_units, sumIfState(toFloat64OrZero(toString(attributes.gram.chat_analysis.scored_cost)), is_work_units_score) AS scored_cost, sumIfState(toInt64OrZero(toString(attributes.gram.chat_analysis.scored_tokens)), is_work_units_score) AS scored_tokens FROM telemetry_logs WHERE (time_unix_nano >= attribute_metrics_cutoff_unix_nano) AND (is_claude_api_request OR is_claude_tool_result OR is_codex_api_request OR is_agent_usage_row OR is_agent_tool_call OR is_work_units_score) GROUP BY gram_project_id, time_bucket, department_name, job_title, employee_type, division_name, cost_center_name, user_email, model, hook_source, roles, groups, account_type, provider, billing_mode, query_source, skill_name, agent_name, mcp_server_name, mcp_tool_name, hook_hostname;
